mapper.select:
SELECT n.id, n.user_id, n.training_id, n.phase_id, n.session_id, n.note_moment, n.content, n.is_private, n.hidden, n.hidden_reason,n.author_id, n.create_time, n.update_time, n2.is_gathered FROM note n LEFT JOIN note n2 ON n2.gathered_note_id = n.id WHERE n.hidden = 0 AND n.is_gathered = 0
AND n.session_id = #{sessionId}
AND n.training_id = #{trainingId}
AND (n.is_private = 0 OR n.user_id = #{userId}) ORDER BY n.note_moment
